def init_session_state():
    defaults = {
        "shortlist_ids": [],
        "custom_compare_flats": [],
        "selected_shortlist_for_compare": [],
        "insights_generated": False,
    }
    for k,v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v

def sync_shortlist_options(valid_ids: List[str]):
    st.session_state.shortlist_ids = [x for x in st.session_state.shortlist_ids if x in valid_ids]
    st.session_state.selected_shortlist_for_compare = [
        x for x in st.session_state.selected_shortlist_for_compare if x in st.session_state.shortlist_ids
    ]

def make_custom_flat_record(ci: UserInputs, asking: float, label: str) -> Dict[str,Any]:
    pred = round(mock_predict_price(ci))
    pct  = round((asking-pred)/pred*100,1)
    seed = sum(ord(c) for c in (ci.town or "Singapore"))
    af   = round(68+(seed%18),1)
    vc   = max(0,min(100,100-abs(pct)*2.5))
    bp   = max(-30,min(30,(ci.budget-asking)/ci.budget*100))
    bc   = max(0,min(100,50+bp*1.5))
    return {
        "listing_id": label,
        "town": ci.town or "Custom location",
        "flat_type": ci.flat_type,
        "floor_area_sqm": ci.floor_area_sqm,
        "storey_range": "Custom input",
        "asking_price": float(asking),
        "predicted_price": float(pred),
        "recent_median_transacted": float(round(pred*0.98)),
        "listing_url": "User-entered flat",
        "asking_vs_predicted_pct": pct,
        "valuation_label": classify_listing(pd.Series({"asking_price":asking,"predicted_price":pred})),
        "amenity_fit_score": af,
        "overall_value_score": round(0.45*vc+0.25*bc+0.30*af,1),
        "comparison_source": "Custom flat",
    }


